/* Generated by Trae Work */
(function () {
  'use strict';

  var cs = getComputedStyle(document.documentElement);
  var colors = {
    bg: cs.getPropertyValue('--bg').trim(),
    bg2: cs.getPropertyValue('--bg2').trim(),
    ink: cs.getPropertyValue('--ink').trim(),
    muted: cs.getPropertyValue('--muted').trim(),
    accent: cs.getPropertyValue('--accent').trim(),
    accent2: cs.getPropertyValue('--accent2').trim(),
    rule: cs.getPropertyValue('--rule').trim(),
    green: cs.getPropertyValue('--green').trim(),
    blue: cs.getPropertyValue('--blue').trim(),
    orange: cs.getPropertyValue('--orange').trim(),
    red: cs.getPropertyValue('--red').trim()
  };

  var dailyChart = null;

  function getItemColor(val) {
    if (val <= 10) return colors.green;
    if (val <= 20) return colors.blue;
    if (val <= 30) return colors.orange;
    return colors.red;
  }

  window.__initDailyChart = function () {
    var data = window.__DAILY_CHART_DATA || [];
    var dates = data.map(function (d) {
      return d.date.substring(5); // "04-16"
    });
    var kwhValues = data.map(function (d) { return d.kwh; });

    var barColors = kwhValues.map(function (v) { return getItemColor(v); });

    var option = {
      animation: true,
      animationDuration: 400,
      renderer: 'svg',
      tooltip: {
        appendToBody: true,
        trigger: 'axis',
        backgroundColor: colors.bg2,
        borderColor: colors.rule,
        textStyle: { color: colors.ink },
        formatter: function (params) {
          var d = data[params[0].dataIndex];
          var level = d.kwh <= 10 ? '低' : d.kwh <= 20 ? '中' : d.kwh <= 30 ? '高' : '很高';
          return d.date + '<br/>' +
            '<span style="color:' + getItemColor(d.kwh) + '">&#9632;</span> 电量: ' +
            d.kwh.toFixed(2) + ' kWh (' + level + ')';
        }
      },
      grid: {
        left: '8%',
        right: '4%',
        top: '10%',
        bottom: '18%'
      },
      xAxis: {
        type: 'category',
        data: dates,
        axisLabel: {
          color: colors.muted,
          rotate: dates.length > 15 ? 45 : 0,
          fontSize: 11,
          interval: dates.length > 20 ? 2 : 0
        },
        axisLine: { lineStyle: { color: colors.rule } },
        axisTick: { lineStyle: { color: colors.rule } }
      },
      yAxis: {
        type: 'value',
        name: 'kWh',
        nameTextStyle: { color: colors.muted, fontSize: 11 },
        axisLabel: { color: colors.muted },
        splitLine: { lineStyle: { color: colors.rule, type: 'dashed' } },
        axisLine: { show: false }
      },
      visualMap: {
        show: false,
        pieces: [
          { lte: 10, color: colors.green },
          { gt: 10, lte: 20, color: colors.blue },
          { gt: 20, lte: 30, color: colors.orange },
          { gt: 30, color: colors.red }
        ]
      },
      series: [
        {
          name: '电量',
          type: 'bar',
          data: kwhValues,
          itemStyle: {
            color: function (params) { return barColors[params.dataIndex]; },
            borderRadius: [3, 3, 0, 0]
          },
          barMaxWidth: dates.length > 25 ? 14 : 24,
          markLine: {
            silent: true,
            lineStyle: { color: colors.accent2, type: 'dashed', width: 1.5 },
            label: { color: colors.accent2, fontSize: 11, formatter: '日均 {c}' },
            data: [{ type: 'average', name: '日均' }]
          }
        },
        {
          name: '趋势',
          type: 'line',
          data: kwhValues,
          smooth: true,
          symbol: 'none',
          lineStyle: { color: colors.accent, width: 1.5, opacity: 0.6 }
        }
      ]
    };

    if (!dailyChart) {
      dailyChart = echarts.init(document.getElementById('chart-daily'), null, { renderer: 'svg' });
      window.addEventListener('resize', function () { dailyChart.resize(); });
    }
    dailyChart.setOption(option, true);
  };

  if (window.__DAILY_CHART_DATA) {
    window.__initDailyChart();
  }
})();